#!/usr/bin/env bash
# ============================================================================
# Architecture Pattern Guard — v{{VERSION}}
# Event: PreToolUse | Matcher: Edit
# Generated by {{PROJECT_NAME}} harness-marketplace plugin
# Reads JSON from stdin (Claude Code v2 hook format)
# Exit: 0 = allow, 2 = deny (Claude sees stderr)
# ============================================================================
set -euo pipefail

# shellcheck disable=SC1091
source "$(dirname "$0")/_log.sh"
# shellcheck disable=SC1091
source "$(dirname "$0")/_parse.sh"

# ═══ GENERATED RULES (overwritten on upgrade) ═══

FILE_PATH="${TOOL_FILE_PATH:-}"

if [[ -z "$FILE_PATH" ]]; then
  exit 0
fi

# Normalize path separators for cross-platform compatibility
FILE_PATH="${FILE_PATH//\\//}"

# Only check source files
case "$FILE_PATH" in
  *.ts|*.tsx|*.js|*.jsx|*.vue|*.py|*.java|*.kt|*.go|*.rs)
    ;;
  *)
    exit 0
    ;;
esac

# Read file content if it exists (for import analysis)
FILE_CONTENT=""
if [[ -f "$FILE_PATH" ]]; then
  FILE_CONTENT="$(cat "$FILE_PATH" 2>/dev/null || true)"
fi

# --------------------------------------------------------------------------
# Feature-Sliced Design (FSD) layer import enforcement
# --------------------------------------------------------------------------
{{CONDITION:fsd}}

# FSD layer hierarchy (higher index = higher layer):
#   0: shared, 1: entities, 2: features, 3: widgets, 4: pages, 5: app
# Lower layers must NOT import from higher layers.

get_fsd_layer_index() {
  local path="$1"
  case "$path" in
    */app/*)      echo 5 ;;
    */pages/*)    echo 4 ;;
    */widgets/*)  echo 3 ;;
    */features/*) echo 2 ;;
    */entities/*) echo 1 ;;
    */shared/*)   echo 0 ;;
    *)            echo -1 ;;
  esac
}

CURRENT_LAYER=$(get_fsd_layer_index "$FILE_PATH")

if [[ "$CURRENT_LAYER" -ge 0 && -n "$FILE_CONTENT" ]]; then
  # Extract import paths from the file
  while IFS= read -r import_path; do
    [[ -z "$import_path" ]] && continue

    # Check FSD alias imports (e.g., @/pages/..., @/app/...)
    IMPORT_LAYER=-1
    case "$import_path" in
      *app/*)      IMPORT_LAYER=5 ;;
      *pages/*)    IMPORT_LAYER=4 ;;
      *widgets/*)  IMPORT_LAYER=3 ;;
      *features/*) IMPORT_LAYER=2 ;;
      *entities/*) IMPORT_LAYER=1 ;;
      *shared/*)   IMPORT_LAYER=0 ;;
    esac

    if [[ "$IMPORT_LAYER" -gt "$CURRENT_LAYER" ]]; then
      LAYER_NAMES=("shared" "entities" "features" "widgets" "pages" "app")
      log_block "pattern-guard" "fsd-layer-violation" "from=${LAYER_NAMES[$CURRENT_LAYER]} to=${LAYER_NAMES[$IMPORT_LAYER]} path=$FILE_PATH"
      echo "[PATTERN] FSD violation in '$FILE_PATH':" >&2
      echo "  Layer '${LAYER_NAMES[$CURRENT_LAYER]}' must not import from '${LAYER_NAMES[$IMPORT_LAYER]}'" >&2
      echo "  Offending import: $import_path" >&2
      echo "  FSD rule: lower layers cannot depend on higher layers." >&2
      exit 2
    fi
  done < <(echo "$FILE_CONTENT" | grep -oE "(from\s+['\"]|import\s+['\"]|require\s*\(\s*['\"])[^'\"]*" | sed "s/.*['\"]//")
fi

{{/CONDITION:fsd}}

# --------------------------------------------------------------------------
# Clean Architecture / Repository Pattern enforcement
# --------------------------------------------------------------------------
{{CONDITION:clean_architecture}}

# Enforce that domain/entity files do not import from infrastructure layer
case "$FILE_PATH" in
  */domain/*|*/entities/*)
    if [[ -n "$FILE_CONTENT" ]]; then
      # Check for infrastructure imports
      if echo "$FILE_CONTENT" | grep -qE "from\s+['\"].*/(infrastructure|infra|database|repository|repositories|adapters)/"; then
        log_block "pattern-guard" "clean-arch-domain-infra" "path=$FILE_PATH"
        echo "[PATTERN] Clean Architecture violation in '$FILE_PATH':" >&2
        echo "  Domain/Entity layer must not import from infrastructure layer." >&2
        echo "  Domain should depend only on abstractions, not implementations." >&2
        exit 2
      fi
      # Check for framework-specific imports in domain
      if echo "$FILE_CONTENT" | grep -qE "from\s+['\"].*(express|fastify|nest|django|flask|spring|gin)/"; then
        log_block "pattern-guard" "clean-arch-domain-framework" "path=$FILE_PATH"
        echo "[PATTERN] Clean Architecture violation in '$FILE_PATH':" >&2
        echo "  Domain layer must not depend on framework-specific code." >&2
        exit 2
      fi
    fi
    ;;
esac

# Enforce that use-cases/services do not import from controllers/presentation
case "$FILE_PATH" in
  */use-cases/*|*/usecases/*|*/application/*|*/services/*)
    if [[ -n "$FILE_CONTENT" ]]; then
      if echo "$FILE_CONTENT" | grep -qE "from\s+['\"].*/(controllers|presentation|views|routes|handlers)/"; then
        log_block "pattern-guard" "clean-arch-usecase-presentation" "path=$FILE_PATH"
        echo "[PATTERN] Clean Architecture violation in '$FILE_PATH':" >&2
        echo "  Application/Use-case layer must not import from presentation layer." >&2
        echo "  Use dependency inversion to decouple these layers." >&2
        exit 2
      fi
    fi
    ;;
esac

{{/CONDITION:clean_architecture}}

